import{_ as l,c as e,a3 as a,o as t}from"./chunks/framework.CAwIQbWu.js";const n=JSON.parse('{"title":"SP篇","description":"","frontmatter":{},"headers":[],"relativePath":"SubjectOne/常识/SP篇.md","filePath":"SubjectOne/常识/SP篇.md","lastUpdated":1737264998000}'),i={name:"SubjectOne/常识/SP篇.md"};function u(c,o,r,h,b,q){return t(),e("div",null,o[0]||(o[0]=[a('<h1 id="sp篇" tabindex="-1">SP篇 <a class="header-anchor" href="#sp篇" aria-label="Permalink to &quot;SP篇&quot;">​</a></h1><h2 id="_1-保险费率" tabindex="-1">1. 保险费率 <a class="header-anchor" href="#_1-保险费率" aria-label="Permalink to &quot;1. 保险费率&quot;">​</a></h2><ul><li>降低</li></ul><blockquote><p>被保险的机动车<code>一年内未发生交通事故</code>，下一年保险费率会<strong>降低</strong>。如果多年没有发生事故，保险费率可以降到最低标准。</p></blockquote><ul><li>上浮</li></ul><blockquote><p>有<code>酒驾</code>或<code>醉驾</code>行为，<strong>交强险</strong>费率将上浮。</p></blockquote><blockquote><p>有酒后驾驶机动车行为的，<strong>机动车交通事故责任强制保险</strong>费率将上浮。</p></blockquote><h2 id="_2-方向盘" tabindex="-1">2. 方向盘 <a class="header-anchor" href="#_2-方向盘" aria-label="Permalink to &quot;2. 方向盘&quot;">​</a></h2><blockquote><p>直线行驶时，车速越快，越不能过多或过快操作转向盘。</p></blockquote><ul><li>降低车速</li><li>握稳方向盘</li></ul><blockquote><p>在<code>大风天气</code>行车，感觉方向难以控制，应降低车速，握稳方向盘，不可急转方向，很容易发生侧翻。</p></blockquote><h2 id="_3-中心线" tabindex="-1">3. 中心线 <a class="header-anchor" href="#_3-中心线" aria-label="Permalink to &quot;3. 中心线&quot;">​</a></h2><ul><li>道路，中间行驶</li></ul><blockquote><p>在没有中心线的道路上行车，机动车应在道路中间行驶，非机动车和行人在两侧通行。</p></blockquote><ul><li>山路，不靠山体的一方先行</li></ul><blockquote><p>在没有中心线的狭窄山路会车，不靠山体的一方相对更危险，拥有优先通行权。</p></blockquote><h2 id="_4-初次申领" tabindex="-1">4. 初次申领 <a class="header-anchor" href="#_4-初次申领" aria-label="Permalink to &quot;4. 初次申领&quot;">​</a></h2><ul><li>机动车号牌、行驶证</li></ul><blockquote><p>初次申领机动车号牌、行驶证的，应当向<strong>住所地</strong>车管所申请注册登记。</p></blockquote><blockquote><p>初次申领的机动车驾驶证的有效期为6年。</p></blockquote><blockquote><p>初次申领驾驶证的驾驶人在实习期内<strong>不得单独</strong>驾驶机动车上高速公路行驶，要有相同或更高准驾车型3年以上驾龄的驾驶人陪同。</p></blockquote><blockquote><p>初次申领驾驶证，可以申请<code>大型货车</code>驾驶证。</p></blockquote><blockquote><p>初次申领机动车驾驶证实习期为一年。</p></blockquote><blockquote><p>轻型牵引挂车不能直接申请，只能通过增驾的形式取得。</p></blockquote><h2 id="_5-证明凭证" tabindex="-1">5. 证明凭证 <a class="header-anchor" href="#_5-证明凭证" aria-label="Permalink to &quot;5. 证明凭证&quot;">​</a></h2><ul><li>免予</li></ul><blockquote><p>对实现信息共享、网上核查的，申请人免予提交相关证明凭证。</p></blockquote><h2 id="_6-遇到横风" tabindex="-1">6. 遇到横风 <a class="header-anchor" href="#_6-遇到横风" aria-label="Permalink to &quot;6. 遇到横风&quot;">​</a></h2><ul><li>（向来风的方向）修正</li></ul><blockquote><p>驾驶机动车行至山谷出口处，遇到横风导致车辆行驶方向偏移时，应双手握稳转向盘，向来风的方向适当修正，力度要轻，不可急转转向盘。</p></blockquote><h2 id="_7-身体条件证明" tabindex="-1">7. 身体条件证明 <a class="header-anchor" href="#_7-身体条件证明" aria-label="Permalink to &quot;7. 身体条件证明&quot;">​</a></h2><ul><li>有效期6个月</li></ul><blockquote><p>身体条件证明的有效期是6个月，过期需重新办理。</p></blockquote><h2 id="_8-发生侧滑" tabindex="-1">8. 发生侧滑 <a class="header-anchor" href="#_8-发生侧滑" aria-label="Permalink to &quot;8. 发生侧滑&quot;">​</a></h2><ul><li>向侧滑的一侧转动转向盘适量修正</li></ul><blockquote><p>泥泞路上发生侧滑，应向侧滑一侧转向方向盘适量修正。</p></blockquote><ul><li>往哪儿滑，方向往哪儿打</li><li>前反后同</li></ul><blockquote><p>侧滑后调整方向：后轮侧滑同向打，前轮侧滑反向打。</p></blockquote><h2 id="_9-注册登记时-无需提交的材料" tabindex="-1">9. 注册登记时，无需提交的材料 <a class="header-anchor" href="#_9-注册登记时-无需提交的材料" aria-label="Permalink to &quot;9. 注册登记时，无需提交的材料&quot;">​</a></h2><ul><li>行驶证</li></ul><blockquote><p>行驶证是机动车注册登记后核发的，申请注册登记时不需要提交。</p></blockquote><h2 id="_10-注册登记时-需要提交的材料" tabindex="-1">10. 注册登记时，需要提交的材料 <a class="header-anchor" href="#_10-注册登记时-需要提交的材料" aria-label="Permalink to &quot;10. 注册登记时，需要提交的材料&quot;">​</a></h2><ul><li>身份证明</li><li>购车发票</li><li>交强险证明</li></ul><h2 id="_11-记分周期-找俩驾驶" tabindex="-1">11. 记分周期（找俩驾驶） <a class="header-anchor" href="#_11-记分周期-找俩驾驶" aria-label="Permalink to &quot;11. 记分周期（找俩驾驶）&quot;">​</a></h2><ul><li>初次领取<strong>机动车驾驶证</strong>之日起</li><li>初次取得<strong>临时机动车驾驶许可</strong>之日起</li></ul><blockquote><p>累积记分周期并不是一定要从驾驶人初次领取机动车驾驶证之日起连续计算，也可以自初次取得临时机动车驾驶许可之日起累积计算。</p></blockquote><h2 id="_12-机动车登记种类-5" tabindex="-1">12. 机动车登记种类（5） <a class="header-anchor" href="#_12-机动车登记种类-5" aria-label="Permalink to &quot;12. 机动车登记种类（5）&quot;">​</a></h2><ul><li>注册登记</li><li>变更登记</li><li>转移登记</li><li>抵押登记</li><li>注销登记</li></ul><h2 id="_13-能量回收不能当制动-刹车" tabindex="-1">13. 能量回收不能当制动（刹车） <a class="header-anchor" href="#_13-能量回收不能当制动-刹车" aria-label="Permalink to &quot;13. 能量回收不能当制动（刹车）&quot;">​</a></h2><blockquote><p>电动汽车的能量回收功能，不得当制动使用。</p></blockquote><h2 id="_14-驾驶自学直考机动车上路学习驾驶" tabindex="-1">14. 驾驶自学直考机动车上路学习驾驶 <a class="header-anchor" href="#_14-驾驶自学直考机动车上路学习驾驶" aria-label="Permalink to &quot;14. 驾驶自学直考机动车上路学习驾驶&quot;">​</a></h2><ul><li>符合自学直考规定</li></ul><blockquote><p>自学直考机动车，需符合自学直考规定才能驾驶该车上路学习驾驶。</p></blockquote><ul><li>不得搭载其他人员</li></ul><blockquote><p>自学直考车中搭载了随车指导人员以外的其他人员，属于违法行为。</p></blockquote><ul><li>指定时间指定道路</li></ul><blockquote><p>自学直考驾照要在有“驾驶训练道路”标志的道路上，按指定时间自学练车，不能随意选择道路。</p></blockquote><ul><li>要用自学车，贴标志，不能用教练车？</li></ul><blockquote><p>申请人在道路上学习驾驶，应当随身携带学习驾驶证明，使用<code>教练车</code>或者<code>学车专用标识签注的自学用车</code>。</p></blockquote><h2 id="_15-上坡先行" tabindex="-1">15. 上坡先行 <a class="header-anchor" href="#_15-上坡先行" aria-label="Permalink to &quot;15. 上坡先行&quot;">​</a></h2><ul><li><p>未上坡的车辆遇到下坡的车已到中途，后者可以先行下坡。</p></li><li><p>窄路会车，上坡先行。</p></li></ul><blockquote><p>狭窄坡路会车，上坡车辆需保持持续的动力输出，加上转向避让等操作，危险性比下坡车辆高，应让上坡一方先行。</p></blockquote><h2 id="_16-边缘30cm" tabindex="-1">16. 边缘30cm <a class="header-anchor" href="#_16-边缘30cm" aria-label="Permalink to &quot;16. 边缘30cm&quot;">​</a></h2><blockquote><p>机动车在道路上临时停车应按顺行方向停车，车身距道路边缘不超过30厘米。</p></blockquote><h2 id="_17-雨天阻力" tabindex="-1">17. 雨天阻力 <a class="header-anchor" href="#_17-雨天阻力" aria-label="Permalink to &quot;17. 雨天阻力&quot;">​</a></h2><ul><li><strong>滚动阻力↓</strong></li><li>空气阻力</li><li>坡度阻力</li><li><strong>滑动阻力↑（如打滑时）</strong></li></ul><blockquote><p>雨天行车路面湿滑，轮胎与地面的摩擦力减小（水膜效应），<strong>滚动阻力减小</strong>，<strong>滑动阻力增大</strong>，<code>车辆行驶阻力会减小</code>，应减速慢行。</p></blockquote><ul><li>更容易加速</li></ul><blockquote><p>雨天<code>行驶阻力减小</code>的体现之一。</p></blockquote><ul><li>刹车距离增加</li></ul><blockquote><p>雨天<code>滑动阻力增大</code>的体现之一。</p></blockquote><h2 id="_18-泥泞阻力" tabindex="-1">18. 泥泞阻力 <a class="header-anchor" href="#_18-泥泞阻力" aria-label="Permalink to &quot;18. 泥泞阻力&quot;">​</a></h2><ul><li><strong>滚动阻力↑</strong></li><li>空气阻力</li><li>坡度阻力</li><li><strong>滑动阻力↑（如打滑时）</strong></li></ul><blockquote><p>轮胎与地面的摩擦力减小（水膜效应），<strong>滑动阻力增大</strong>，看似滚动阻力应减小，但是泥泞路面松软粘稠，轮胎与地面的附着力减小，车轮在滚动时需要克服更多的形变和阻力，因此<strong>滚动阻力实际增大</strong>，<code>车辆行驶阻力会增大</code>，易打滑或发生侧滑。</p></blockquote><h2 id="_19-礼让校车" tabindex="-1">19. 礼让校车 <a class="header-anchor" href="#_19-礼让校车" aria-label="Permalink to &quot;19. 礼让校车&quot;">​</a></h2><ul><li>停车等待</li></ul><blockquote><p>校车在同方向只有<code>1</code>条机动车道的道路上停靠时，后方车辆应当停车等待，不得超越。 校车在同方向只有<code>2</code>条机动车道的道路上停靠时，后方和相邻机动车道上的机动车应当停车等待，不得超越，其他机动车道上的机动车应当减速通过。</p></blockquote><ul><li>不得鸣喇叭、使用灯光催促</li></ul><blockquote><p>校车后方停车等待的机动车不得鸣喇叭或者使用灯光催促校车。</p></blockquote><h2 id="_20-预约次数限制" tabindex="-1">20. 预约次数限制 <a class="header-anchor" href="#_20-预约次数限制" aria-label="Permalink to &quot;20. 预约次数限制&quot;">​</a></h2><ul><li>分别5次</li></ul><blockquote><p>科目二和科目三分别不得超过5次，不是合计5次。 科目二和科目三只有5次考试机会，有效期为3年，从科目一考试合格后开始算起。</p></blockquote><h2 id="_21-绕车检查" tabindex="-1">21. 绕车检查 <a class="header-anchor" href="#_21-绕车检查" aria-label="Permalink to &quot;21. 绕车检查&quot;">​</a></h2><ul><li>逆时针绕车一周</li></ul><blockquote><p>上车前，驾驶人应逆时针绕车一周检查，确认安全再上车。</p></blockquote><h2 id="_22-停车视距-不启动" tabindex="-1">22. 停车视距（不启动） <a class="header-anchor" href="#_22-停车视距-不启动" aria-label="Permalink to &quot;22. 停车视距（不启动）&quot;">​</a></h2><ul><li>反应距离</li><li>制动距离</li><li>安全距离</li></ul><blockquote><p>停车视距包括反应距离、制动距离和安全距离。</p></blockquote><h2 id="_23-清扫车" tabindex="-1">23. 清扫车 <a class="header-anchor" href="#_23-清扫车" aria-label="Permalink to &quot;23. 清扫车&quot;">​</a></h2><ul><li>可不受车辆分道行驶的限制</li></ul><blockquote><p>在道路上作业的清扫车在不影响其他车辆通行的情况下，可不受车辆分道行驶的控制。</p></blockquote><h2 id="_24-保持较大的跟车距离" tabindex="-1">24. 保持较大的跟车距离 <a class="header-anchor" href="#_24-保持较大的跟车距离" aria-label="Permalink to &quot;24. 保持较大的跟车距离&quot;">​</a></h2><ul><li>溅起来的水会影响视线</li></ul><blockquote><p>路面有积水，前车经过，溅起的水花会影响驾驶员视线，安全起见，应保持较大的跟车距离。</p></blockquote><h2 id="_25-有异议10-交罚款15-窗口期" tabindex="-1">25. 有异议10，交罚款15（窗口期） <a class="header-anchor" href="#_25-有异议10-交罚款15-窗口期" aria-label="Permalink to &quot;25. 有异议10，交罚款15（窗口期）&quot;">​</a></h2><blockquote><p>当事人应在收到罚款行政处罚书的当日起15日内，到指定银行缴纳罚款。</p></blockquote><h2 id="_26-交通事故-自行协商" tabindex="-1">26. 交通事故（自行协商） <a class="header-anchor" href="#_26-交通事故-自行协商" aria-label="Permalink to &quot;26. 交通事故（自行协商）&quot;">​</a></h2><ul><li>驾驶人未携带身份证的</li></ul><blockquote><p>机动车之间发生的造成车物损失或人员<code>轻微</code>伤，且车辆能移动的交通事故，若车辆<code>无号牌</code>的、驾驶人<code>无驾驶证</code>的、驾驶人<code>饮酒</code>的，都应保护现场并立即报警。选项中只有驾驶人未携带身份证的，可自行协商解决。</p></blockquote><blockquote><p>驾驶机动车在道路上发生事故，未造成人身伤亡或仅造成<code>轻微</code>财产损失，基本事实清楚，当事人对事实及成因<code>无争议</code>的，可以即行撤离现场，恢复交通，自行协商处理损害赔偿事宜。</p></blockquote><h2 id="_27-牵引故障车车速" tabindex="-1">27. 牵引故障车车速 <a class="header-anchor" href="#_27-牵引故障车车速" aria-label="Permalink to &quot;27. 牵引故障车车速&quot;">​</a></h2><ul><li>牵引故障车车速不得超过30，车距150</li></ul><blockquote><p>牵引故障车时，牵引与被牵引的机动车都要开启危险报警闪光灯，最高行驶速度不得超过30公里/小时。</p></blockquote><h2 id="_28-卖车不用驾驶证" tabindex="-1">28. 卖车不用驾驶证 <a class="header-anchor" href="#_28-卖车不用驾驶证" aria-label="Permalink to &quot;28. 卖车不用驾驶证&quot;">​</a></h2><blockquote><p>申请转让登记，需要提交的主要是跟机动车相关的资料，不包括驾驶证。</p></blockquote><blockquote><p>机动车所有人申请转移登记前，应当将涉及该车的道路交通安全违法行为和交通事故处理完毕。</p></blockquote><h2 id="_29-补发补领15天-号牌" tabindex="-1">29. 补发补领15天（号牌） <a class="header-anchor" href="#_29-补发补领15天-号牌" aria-label="Permalink to &quot;29. 补发补领15天（号牌）&quot;">​</a></h2><blockquote><p>车辆管理所收到机动车所有人补领、换领机动车号牌的申请后，自受理之日起15日内补发、换发号牌。</p></blockquote><h2 id="_30-安全枕放后脑勺" tabindex="-1">30. 安全枕放后脑勺 <a class="header-anchor" href="#_30-安全枕放后脑勺" aria-label="Permalink to &quot;30. 安全枕放后脑勺&quot;">​</a></h2><ul><li>头枕中心与后脑勺中心平齐，不是正对颈椎</li></ul><blockquote><p>头枕应对准驾驶员的后脑中心，不是颈椎。</p></blockquote><blockquote><p>如果安全头枕调整不到位，发生交通事故时，驾驶人的颈椎会受到一定程度的伤害。</p></blockquote><h2 id="_31-事后三日-作出是否受理" tabindex="-1">31. 事后三日，作出是否受理 <a class="header-anchor" href="#_31-事后三日-作出是否受理" aria-label="Permalink to &quot;31. 事后三日，作出是否受理&quot;">​</a></h2><blockquote><p>现机动车所有人住所不在车辆管理所管辖区域内的，转出地车辆管理所应当自受理之日起3日内，查验机动车。</p></blockquote><h2 id="_32-下长坡连续制动-刹车" tabindex="-1">32. 下长坡连续制动（刹车） <a class="header-anchor" href="#_32-下长坡连续制动-刹车" aria-label="Permalink to &quot;32. 下长坡连续制动（刹车）&quot;">​</a></h2><blockquote><p>下长坡时，长时间使用行车制动器制动会使刹车片温度升高，制动效果变差，甚至会刹车失灵。</p></blockquote><h2 id="_33-正在被超越时" tabindex="-1">33. 正在被超越时 <a class="header-anchor" href="#_33-正在被超越时" aria-label="Permalink to &quot;33. 正在被超越时&quot;">​</a></h2><ul><li>减速靠右让行</li></ul><blockquote><p>驾驶车辆正在被超越时，应减速靠右让行，保证有足够的横向安全距离。</p></blockquote><h2 id="_34-超车都只能从左侧超" tabindex="-1">34. 超车都只能从左侧超 <a class="header-anchor" href="#_34-超车都只能从左侧超" aria-label="Permalink to &quot;34. 超车都只能从左侧超&quot;">​</a></h2><ul><li>不得从右侧超车</li></ul><h2 id="_35-不得停车口诀-口5站3" tabindex="-1">35. 不得停车口诀：口5站3 <a class="header-anchor" href="#_35-不得停车口诀-口5站3" aria-label="Permalink to &quot;35. 不得停车口诀：口5站3&quot;">​</a></h2><ul><li>口5</li></ul><blockquote><p>指<code>交叉路口</code>、<code>铁路道口</code>、<code>弯道</code>、<code>弯度不足4米的窄路</code>、<code>隧道</code>等路口50米以内不得停车。</p></blockquote><ul><li>站3</li></ul><blockquote><p>指<code>公交站</code>、<code>加油站</code>、<code>消防站</code>等站点30米以内不得停车。</p></blockquote><h2 id="_36-临牌15日" tabindex="-1">36. 临牌15日 <a class="header-anchor" href="#_36-临牌15日" aria-label="Permalink to &quot;36. 临牌15日&quot;">​</a></h2><blockquote><p>补发、换发号牌期间，车辆管理所应当核发有效期不超过15日的临时行驶车号牌。</p></blockquote><h2 id="_37-驾驶证审验内容" tabindex="-1">37. 驾驶证审验内容 <a class="header-anchor" href="#_37-驾驶证审验内容" aria-label="Permalink to &quot;37. 驾驶证审验内容&quot;">​</a></h2><ul><li>身体是否有妨碍安全驾驶的疾病</li></ul><blockquote><p>驾驶证审验是在驾驶证有效期满换证时，需要检验驾驶人的身体情况，与机动车相关情况无关。注意，有证的人不一定有车。</p></blockquote><h2 id="_38-泊车位" tabindex="-1">38. 泊车位 <a class="header-anchor" href="#_38-泊车位" aria-label="Permalink to &quot;38. 泊车位&quot;">​</a></h2><blockquote><p>蓝免白收黄专属</p></blockquote><ul><li>蓝免</li></ul><blockquote><p>颜色为蓝色的泊车位，表示此停车位为免费停车位，适用于政府部门办公场地周边规划的泊车位。</p></blockquote><ul><li>白收</li></ul><blockquote><p>颜色为白色的泊车位，表示此停车位为收费停车位，多位于人行道及退缩线上，适用于交投公司停车收费管理。</p></blockquote><ul><li>黄专属</li></ul><blockquote><p>颜色为黄色的泊车位，表示此停车位为专属停车位，适用于承租的车位或有关单位申请设置的，供办公、方便群众车辆停放的车位。</p></blockquote><h2 id="_39-临时号牌留3日" tabindex="-1">39. 临时号牌留3日 <a class="header-anchor" href="#_39-临时号牌留3日" aria-label="Permalink to &quot;39. 临时号牌留3日&quot;">​</a></h2><blockquote><p>机动车办理登记后，机动车所有人收到机动车号牌之日起三日后，临时行驶车号牌作废，不得继续使用。</p></blockquote><h2 id="_40-左转转大弯-右转转小弯" tabindex="-1">40. 左转转大弯，右转转小弯 <a class="header-anchor" href="#_40-左转转大弯-右转转小弯" aria-label="Permalink to &quot;40. 左转转大弯，右转转小弯&quot;">​</a></h2><blockquote><p>我国机动车是靠右侧行驶，转弯应靠右侧转弯，左转转大弯，右转转小弯，可最大程度避免发生碰撞。</p></blockquote><h2 id="_41-申领检验标志" tabindex="-1">41. 申领检验标志 <a class="header-anchor" href="#_41-申领检验标志" aria-label="Permalink to &quot;41. 申领检验标志&quot;">​</a></h2><blockquote><p>非营运小微型载客汽车自注册登记之日起<code>10</code>年内，每<code>2</code>年检验一次。</p></blockquote><h2 id="_42-预约科目三" tabindex="-1">42. 预约科目三 <a class="header-anchor" href="#_42-预约科目三" aria-label="Permalink to &quot;42. 预约科目三&quot;">​</a></h2><ul><li>取得准考证明满20日后</li></ul><blockquote><p>小型自动挡科目三，要在科目一通过20日后才可以预约；小型汽车科目三，要在科目一通过后30日才可以预约。</p></blockquote><blockquote><p>报考小型自动挡汽车准驾车型科目三考试的，应在取得驾驶技能准考证明满<code>20</code>日后预约考试。</p></blockquote><h2 id="_43-身体证明" tabindex="-1">43. 身体证明 <a class="header-anchor" href="#_43-身体证明" aria-label="Permalink to &quot;43. 身体证明&quot;">​</a></h2><blockquote><p>办理残疾人专用小型自动挡载客汽车驾驶证提交的身体证明，只能由<code>省级卫生健康行政部门认定的</code>专门医疗机构出具。</p></blockquote><h2 id="_44-申请危险货物运输车" tabindex="-1">44. 申请危险货物运输车 <a class="header-anchor" href="#_44-申请危险货物运输车" aria-label="Permalink to &quot;44. 申请危险货物运输车&quot;">​</a></h2><blockquote><p>申请危险货物运输车登记的，机动车所有人应当为<code>单位</code>。</p></blockquote><h2 id="_45-学习驾驶证有效3年" tabindex="-1">45. 学习驾驶证有效3年 <a class="header-anchor" href="#_45-学习驾驶证有效3年" aria-label="Permalink to &quot;45. 学习驾驶证有效3年&quot;">​</a></h2><blockquote><p>学习驾驶证明的有效期是3年，从科目一考试合格后开始算起。如果截止日期超过年龄上限，学习驾驶证明自动作废。</p></blockquote><h2 id="_46-在一个记分周期内两次以上达到12分" tabindex="-1">46. 在一个记分周期内两次以上达到12分 <a class="header-anchor" href="#_46-在一个记分周期内两次以上达到12分" aria-label="Permalink to &quot;46. 在一个记分周期内两次以上达到12分&quot;">​</a></h2><ul><li>自动20手动30</li></ul><blockquote><p>一个记分周期内累积两次以上达到12分的，应在通过科目一考试后30日内进行科目三考试。 小型自动挡科目三，要在科目一通过20日后才可以预约；小型汽车科目三，要在科目一通过后30日才可以预约。</p></blockquote><h2 id="_47-c6-24-c5-23" tabindex="-1">47. c6-24,c5-23 <a class="header-anchor" href="#_47-c6-24-c5-23" aria-label="Permalink to &quot;47. c6-24,c5-23&quot;">​</a></h2><ul><li>增驾C6科2科4</li><li>变驾C5（残疾）科2科3，加法记忆</li></ul><blockquote><p>因身体条件发生变化，申请变更为残疾人专用小型自动挡载客汽车，需要考科目二和科目三。</p></blockquote><h2 id="_48-审30" tabindex="-1">48. 审30 <a class="header-anchor" href="#_48-审30" aria-label="Permalink to &quot;48. 审30&quot;">​</a></h2><blockquote><p>事故造成人员死亡，承担同等以上责任未被吊销驾驶证的，应当在记分周期结束后<strong>30</strong>日内接受审验。</p></blockquote><h2 id="_49-户籍地以外无居住" tabindex="-1">49. 户籍地以外无居住 <a class="header-anchor" href="#_49-户籍地以外无居住" aria-label="Permalink to &quot;49. 户籍地以外无居住&quot;">​</a></h2><blockquote><p>在户籍地以外办理小型、微型非营运载客汽车注册登记的，可免予提交公安机关核发的居住证明或居住登记证明。</p></blockquote><h2 id="_50-户籍地以外居住" tabindex="-1">50. 户籍地以外居住 <a class="header-anchor" href="#_50-户籍地以外居住" aria-label="Permalink to &quot;50. 户籍地以外居住&quot;">​</a></h2><blockquote><p>在户籍地以外居住的，可以在居住地车管所申请机动车驾驶证。</p></blockquote><h2 id="_51-现役军人申请机动车驾驶证" tabindex="-1">51. 现役军人申请机动车驾驶证 <a class="header-anchor" href="#_51-现役军人申请机动车驾驶证" aria-label="Permalink to &quot;51. 现役军人申请机动车驾驶证&quot;">​</a></h2><blockquote><p>现役军人可就近在部队驻地车管所申请驾驶证。</p></blockquote>',169)]))}const k=l(i,[["render",u]]);export{n as __pageData,k as default};
